#!/usr/bin/env bash
# deck-storyline.sh — Deck / storyline 构建（核心手艺） SOP walkthrough for 管理咨询.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="管理咨询"
WORKFLOW="Deck / storyline 构建（核心手艺）"

usage() {
  cat <<EOF
deck-storyline.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./deck-storyline.sh             # interactive
  ./deck-storyline.sh --dry-run
  ./deck-storyline.sh --json
  ./deck-storyline.sh --explain
  ./deck-storyline.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Deck / storyline 构建（核心手艺）" 工作流。

一句话: 把分析结论变成高管能秒懂、能决策的 deck —— 经「定 governing thought → SCQA 开场 → 搭 ghost deck 骨架 → 写 action title（每页一句话结论）→ 填数据图 → so-what 自检 → review」。deck 是咨询的母语，这是这一行最核心、最难替代的手艺。

入门 SOP 共 7 步, 失败模式自检 6 项。

相关心智模型:
  • 假设驱动是地图不是答案：先射箭再画靶 ⇄ 随时 kill 假设（第一性张力）: 面对模糊大问题，资深咨询人不从穷举数据出发，而是 Day-1 就基于经验立一个**可证伪**的初步答案（hypothesis / initial hypothesis）当地图，再只做能 kill 或 
  • 战略 = 做选择 / 做不同，不是运营效率、不是愿望清单: 这行顶级战略 figure 跨流派一致——战略的本质是**逼自己做取舍**（Martin：where-to-play × how-to-win 两个不可分割的选择；Rumelt：kernel = 诊断

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定 governing thought（统领思想）**：先确定整个 deck 要传达的那**一句话核心结论 / 建议**（金字塔塔尖）。(evidence: [T04-S001])"
  "**SCQA 搭开场故事线**：用 Situation（情境）→ Complication（冲突）→ Question（疑问）→ Answer（回答 = governing thought）框住「为什么现在要解决这个、答案是什么」。(evidence: [T04-S001, T06-S015])"
  "**搭 ghost deck（鬼影稿 / 骨架先行）**：做一份 ~20% 完成度的骨架 —— 只写每页的 action title + 占位空白 exhibit，**先把整条论证逻辑（storyline）跑通并对齐**，再碰数据和美化。「never open PowerPoint until your logic is flawless」。(evidence: [T03-S015, T06-S015])"
  "**写 action title（每页一句话结论）**：每页标题写成**完整结论句**（「收入因低端机型萎缩下滑 12%」）而非主题词（「收入分析」），一页一条信息。(evidence: [T04-S001, T06-S015])"
  "**填数据图（exhibit）**：每页配一个支撑该 action title 的图表（waterfall / Marimekko / 趋势图），think-cell 一键生成 + 链 Excel。(evidence: [T02-S001])"
  "**so-what 自检**：逐页问「这页的 so-what 是什么 / 对决策意味着什么」；把所有 action title 串起来读，检查是不是一条完整论证 = 这就是 executive summary。(evidence: [T06-S009, T04-S001])"
  "**Review（EM/partner 审）**：资深人按「storyline 通不通 / action title 是不是结论句 / 图表卫生 / so-what 够不够硬」过一遍，反复打磨。(evidence: [T03-S008review-rubric, T03-S015])"
)
declare -a FAILURE_MODES=(
  "**先做精美页、后想 storyline（不用 ghost deck）**：方向一改几十页全废。避免：storyline/ghost deck 没敲定前不碰美化。**自检**：「我现在的 PPT，逻辑链跑通了吗？还是在没想清楚时就开始排版？」"
  "**action title 写成主题词而非结论句**：「市场概览」而非「该市场年增 18%、值得进入」。避免：每个标题强制写成有主谓宾的断言。**自检**：「只读这页标题，读者知道我的结论吗？还是只知道这页『讲什么』？」"
  "**结论埋在最后（违背结论先行）**：按分析/时间顺序讲，把 answer 放第 40 页。避免：金字塔 —— governing thought 开头就给。**自检**：「高管只看前 3 页 exec summary，能拿到全部建议吗？」"
  "**填了一堆图但答不出 so-what**：exhibit 漂亮但没洞见跳跃。避免：每页过 so-what 自检。**自检**：「这页的图说明了什么 → 所以客户该做什么？答不出就删或重做。」"
  "**action titles 连读不成一篇论证**：单页对、整体散。避免：抽出所有 action title 连读，补断点。**自检**：「把所有标题抄下来连读，是不是一篇完整的『诊断 → 所以建议 X』？」"
  "**GenAI 造的 slide 数据没核验就交**（新增，decay HIGH）：Deckster/Copilot 出的图表数字可能是幻觉。避免：AI 生成内容人工核验落到来源（Deloitte 退款殷鉴）。**自检**：「这张 AI 生成的图，数字我对过原始数据了吗？」(evidence: [T03-S009])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "deck-storyline-walkthrough"
fi
